const now = new Date();
const ts = now.toISOString().slice(0, 19).replace("T", " " );

const temperatura = 24 + (Math.random() * 8);
let gas = 2800 + Math.floor(Math.random() * 1200);

if (temperatura > 29 || Math.random() > 0.82) {
    gas = 3600 + Math.floor(Math.random() * 500);
}

msg.payload = {
    device_id: "SIM-Cocina-02",
    zona: "Cocina-Simulada-02",
    temperatura_C: Number(temperatura.toFixed(2)),
    mq135_aire: gas,
    timestamp: ts
};

return msg;

const UMBRAL_TEMP = 28.0;
const UMBRAL_GAS = 3600;
const INTERVALO_NORMAL_SEG = 6;
const INTERVALO_ALERTA_SEG = 3;
const INTERVALO_EMERGENCIA_SEG = 1;
const TOPICO_COMANDOS = "alejandro.bravo_isa@uao.edu.co/comandos";

const p = (typeof msg.payload === "object" && msg.payload !== null) ? msg.payload : {};

function toNumber(v) {
    if (v === null || v === undefined || v === "") return NaN;
    const n = Number(v);
    return Number.isFinite(n) ? n : NaN;
}

const temperatura = toNumber(p.temperatura_C ?? p.temperatura ?? p.temp);
const gas = toNumber(p.mq135_aire ?? p.gas ?? p.mq135);

let estado = "";
let detalle = "";
let motivoActuadores = "";
let intervaloSeg = INTERVALO_NORMAL_SEG;
let acciones = {
    led: "VERDE",
    extractor: "APAGADO",
    sirena: "APAGADA",
    valvula_gas: "ABIERTA"
};

if (Number.isFinite(temperatura) && Number.isFinite(gas)) {
    const temperaturaAlta = temperatura >= UMBRAL_TEMP;
    const gasAlto = gas >= UMBRAL_GAS;

    if (temperaturaAlta && gasAlto) {
        estado = "EMERGENCIA";
        intervaloSeg = INTERVALO_EMERGENCIA_SEG;
        detalle = "Temperatura y gas altos";
        motivoActuadores = "Activacion por temperatura y gas altos";
        acciones = {
            led: "ROJO",
            extractor: "ENCENDIDO",
            sirena: "ENCENDIDA",
            valvula_gas: "CERRADA"
        };
    } else if (temperaturaAlta) {
        estado = "ALERTA";
        intervaloSeg = INTERVALO_ALERTA_SEG;
        detalle = "Temperatura alta";
        motivoActuadores = "Activacion por temperatura fuera de rango";
        acciones = {
            led: "AMARILLO",
            extractor: "ENCENDIDO",
            sirena: "APAGADA",
            valvula_gas: "ABIERTA"
        };
    } else if (gasAlto) {
        estado = "ALERTA";
        intervaloSeg = INTERVALO_ALERTA_SEG;
        detalle = "Gas alto";
        motivoActuadores = "Activacion por gas fuera de rango";
        acciones = {
            led: "AMARILLO",
            extractor: "ENCENDIDO",
            sirena: "APAGADA",
            valvula_gas: "ABIERTA"
        };
    } else {
        estado = "NORMAL";
        intervaloSeg = INTERVALO_NORMAL_SEG;
        detalle = "Valores dentro de rango";
        motivoActuadores = "Sin activacion, condiciones normales";
        acciones = {
            led: "VERDE",
            extractor: "APAGADO",
            sirena: "APAGADA",
            valvula_gas: "ABIERTA"
        };
    }
} else {
    estado = String(p.estado_riesgo || "INVALIDO").toUpperCase();
    detalle = "No llegaron temperatura_C y mq135_aire; se conserva estado recibido";
    motivoActuadores = "Datos incompletos";
}

msg.payload.temperatura_C = Number.isFinite(temperatura) ? temperatura : p.temperatura_C;
msg.payload.mq135_aire = Number.isFinite(gas) ? gas : p.mq135_aire;
msg.payload.estado_riesgo = estado;
msg.payload.tiempo_espera_seg = intervaloSeg;
msg.payload.detalle_estado = detalle;
msg.payload.motivo_actuadores = motivoActuadores;
msg.payload.actuadores = acciones;

const deviceIdHist = String(msg.payload.device_id || "ALL");
const histKey = `hist_estados_${deviceIdHist}`;
const historialPrevio = context.get(histKey) || [];
const historialRecortado = historialPrevio.slice(-3);
const historialFinal = [...historialRecortado, estado];
context.set(histKey, historialFinal);
msg.payload.historial_reciente = historialFinal.join(">");

if (estado === "NORMAL") {
    node.status({ fill: "green", shape: "dot", text: `NORMAL | ${intervaloSeg}s` });
} else if (estado === "ALERTA") {
    node.status({ fill: "yellow", shape: "dot", text: `ALERTA | ${intervaloSeg}s` });
} else if (estado === "EMERGENCIA") {
    node.status({ fill: "red", shape: "dot", text: `EMERGENCIA | ${intervaloSeg}s` });
} else {
    node.status({ fill: "grey", shape: "ring", text: estado });
}

const resumen = {
    topic: msg.topic,
    payload: {
        device_id: msg.payload.device_id || "N/A",
        estado: estado,
        temperatura_C: msg.payload.temperatura_C,
        mq135_aire: msg.payload.mq135_aire,
        detalle: detalle,
        motivo_actuadores: motivoActuadores,
        actuadores: acciones,
        intervalo_envio_seg: intervaloSeg,
        timestamp: msg.payload.timestamp || null
    }
};

const deviceId = String(msg.payload.device_id || "ALL");
const estadoKey = `estado_prev_${deviceId}`;
const estadoPrev = context.get(estadoKey);
let comando = null;

if (["NORMAL", "ALERTA", "EMERGENCIA"].includes(estado) && estado !== estadoPrev) {
    context.set(estadoKey, estado);
    comando = {
        topic: TOPICO_COMANDOS,
        payload: JSON.stringify({
            device_id: deviceId,
            estado: estado,
            intervalo_seg: intervaloSeg
        }),
        qos: "1",
        retain: false
    };
}

return [msg, resumen, comando];

const p = msg.payload || {};

const temp = Number(p.temperatura_C);
const gas = Number(p.mq135_aire);
if (!Number.isFinite(temp) || !Number.isFinite(gas)) {
    return null;
}

const deviceId = String(p.device_id || "ESP32");
const zona = String(p.zona || "N/A");
const estado = String(p.estado_riesgo || "INVALIDO").toUpperCase();
const detalle = String(p.detalle_estado || "");
const motivoActuadores = String(p.motivo_actuadores || "Sin motivo");
const historialReciente = String(p.historial_reciente || estado);
const espera = Number(p.tiempo_espera_seg);
const tiempoEspera = Number.isFinite(espera) ? Number(espera.toFixed(2)) : null;
let ts = String(p.timestamp || "");

if (!ts) {
    const now = new Date();
    ts = now.toISOString().slice(0, 19).replace("T", " " );
}

msg.deviceId = deviceId;
msg.estadoRiesgo = estado;
msg.detalleEstado = detalle;
msg.tiempoEspera = tiempoEspera;
msg.motivoActuadores = motivoActuadores;
msg.historialReciente = historialReciente;
msg.actuadores = p.actuadores || {};

msg.topic = "INSERT INTO mediciones_brutas (device_id, zona, temperatura_c, mq135_aire, timestamp_origen) VALUES (?, ?, ?, ?, ?)";
msg.payload = [
    deviceId,
    zona,
    Number(temp.toFixed(2)),
    Math.round(gas),
    ts
];
msg.queryType = "insert_bruta";

return msg;

const medicionId = Number(msg.payload && msg.payload.insertId);
if (!Number.isFinite(medicionId) || medicionId <= 0) {
    return null;
}

msg.medicionId = medicionId;
msg.topic = "INSERT INTO estados_medicion (medicion_id, estado_riesgo, detalle_estado, tiempo_espera_seg) VALUES (?, ?, ?, ?)";
msg.payload = [
    medicionId,
    String(msg.estadoRiesgo || "INVALIDO").toUpperCase(),
    String(msg.detalleEstado || ""),
    msg.tiempoEspera
];
msg.queryType = "insert_estado";
return msg;

const medicionId = Number(msg.medicionId);
if (!Number.isFinite(medicionId) || medicionId <= 0) {
    return null;
}

const a = msg.actuadores || {};
const estado = String(msg.estadoRiesgo || "INVALIDO").toUpperCase();
const historialReciente = String(msg.historialReciente || estado);

msg.topic = "INSERT INTO eventos_actuadores (medicion_id, device_id, estado_riesgo, motivo_activacion, historial_reciente, led_estado, extractor_estado, sirena_estado, valvula_gas_estado) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)";
msg.payload = [
    medicionId,
    String(msg.deviceId || "ESP32"),
    estado,
    String(msg.motivoActuadores || "Sin motivo"),
    historialReciente,
    String(a.led || "N/A"),
    String(a.extractor || "N/A"),
    String(a.sirena || "N/A"),
    String(a.valvula_gas || "N/A")
];
msg.queryType = "insert_actuador";
return msg;

const token = String(msg.payload || "").trim().toUpperCase();
const baseJoin = "SELECT m.id, m.device_id, m.zona, m.temperatura_c, m.mq135_aire, e.estado_riesgo, e.detalle_estado, e.tiempo_espera_seg, m.timestamp_origen, m.created_at FROM mediciones_brutas m INNER JOIN estados_medicion e ON e.medicion_id = m.id";

if (["NORMAL", "ALERTA", "EMERGENCIA"].includes(token)) {
    msg.topic = `${baseJoin} WHERE e.estado_riesgo='${token}' ORDER BY m.id DESC LIMIT 20;`;
} else if (token === "RESUMEN_ALERTAS") {
    msg.topic = "SELECT estado_riesgo, COUNT(*) AS total, MAX(created_at) AS ultima_medicion FROM estados_medicion WHERE estado_riesgo IN ('ALERTA','EMERGENCIA') GROUP BY estado_riesgo ORDER BY total DESC;";
} else if (token === "BRUTAS_RECIENTES") {
    msg.topic = "SELECT id, device_id, zona, temperatura_c, mq135_aire, timestamp_origen, created_at FROM mediciones_brutas ORDER BY id DESC LIMIT 20;";
} else if (token === "ACTUADORES_RECIENTES") {
    msg.topic = "SELECT id, medicion_id, device_id, estado_riesgo, motivo_activacion, historial_reciente, led_estado, extractor_estado, sirena_estado, valvula_gas_estado, created_at FROM eventos_actuadores ORDER BY id DESC LIMIT 20;";
} else {
    msg.topic = `${baseJoin} ORDER BY m.id DESC LIMIT 20;`;
}

msg.queryType = "select";
msg.payload = [];
return msg;

const p = msg.payload || {};
const estado = p.estado || p.estado_riesgo || "N/A";
const a = p.actuadores || {};
const deviceId = String(p.device_id || "N/A");

return [
  { payload: `LED=${a.led || "N/A"} | estado=${estado} | device=${deviceId}` },
  { payload: `Extractor=${a.extractor || "N/A"} | estado=${estado} | device=${deviceId}` },
  { payload: `Sirena=${a.sirena || "N/A"} | estado=${estado} | device=${deviceId}` },
  { payload: `Valvula gas=${a.valvula_gas || "N/A"} | estado=${estado} | device=${deviceId}` }
];

const p = msg.payload || {};
const estado = p.estado || p.estado_riesgo || "N/A";
const a = p.actuadores || {};
const deviceId = String(p.device_id || "N/A");

return [
  { payload: `LED=${a.led || "N/A"} | estado=${estado} | device=${deviceId}` },
  { payload: `Extractor=${a.extractor || "N/A"} | estado=${estado} | device=${deviceId}` },
  { payload: `Sirena=${a.sirena || "N/A"} | estado=${estado} | device=${deviceId}` },
  { payload: `Valvula gas=${a.valvula_gas || "N/A"} | estado=${estado} | device=${deviceId}` }
];

const rows = Array.isArray(msg.payload) ? msg.payload : [];

if (rows.length === 0) {
    msg.payload = "Sin resultados";
    return msg;
}

const safe = (v) => String(v ?? "");
const maxRows = 20;
const data = rows.slice(0, maxRows);

const preferred = [
    "id",
    "medicion_id",
    "device_id",
    "zona",
    "temperatura_c",
    "mq135_aire",
    "estado_riesgo",
    "detalle_estado",
    "tiempo_espera_seg",
    "timestamp_origen",
    "created_at"
];

const cols = Object.keys(data[0] || {}).sort((a, b) => {
    const ia = preferred.indexOf(a);
    const ib = preferred.indexOf(b);
    const va = ia === -1 ? 999 : ia;
    const vb = ib === -1 ? 999 : ib;
    if (va !== vb) return va - vb;
    return a.localeCompare(b);
});

if (cols.length === 0) {
    msg.payload = "Sin columnas para mostrar";
    return msg;
}

const widths = cols.map((c) => c.length);
for (const r of data) {
    cols.forEach((c, i) => {
        const l = safe(r[c]).length;
        if (l > widths[i]) widths[i] = Math.min(l, 32);
    });
}

const trunc = (s, w) => (s.length > w ? s.slice(0, w - 1) + "..." : s);
const pad = (s, w) => trunc(s, w).padEnd(w, " " );

const header = cols.map((c, i) => pad(c, widths[i])).join(" | " );
const sep = widths.map((w) => "-".repeat(w)).join("-+-");
const body = data.map((r) => cols.map((c, i) => pad(safe(r[c]), widths[i])).join(" | " )).join("\n");

msg.payload = `Filas devueltas: ${rows.length}\n\n${header}\n${sep}\n${body}`;
return msg;
